class Admin_Model_NewsCategory extends Admin_Model_Base_NewsCategory {

    public static function formatCategoryTree(): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_NewsCategory object');
        $query->select('object.ID, object.NewsCategory_ID, newsCategoryLangs.Name as Name');
        $query->leftJoin('object.newsCategoryLangs newsCategoryLangs WITH Language_ID = 1');
        $resultArray = $query->execute()->toArray();

        $result = array();

        foreach ($resultArray as $item) {
            $itemItem = array();
            $itemItem['id'] = $item['ID'];
            $itemItem['NewsCategory_ID'] = $item['NewsCategory_ID'];
            $itemItem['text'] = $item['Name'];
            $result[] = $itemItem;
        }

        $dangling = array();
        $output = array();
        $all = array();

        foreach ($result as $entry) {
            $entry['children'] = array();
            $id = $entry['id'];

            if ($entry['NewsCategory_ID'] == '') {
                $all[$id] = $entry;
                $output[] = & $all[$id];
            } else {
                $dangling[$id] = $entry;
            }
        }

        while (count($dangling) > 0) {
            foreach ($dangling as $entry) {
                $id = $entry['id'];
                $pid = $entry['NewsCategory_ID'];

                if (isset($all[$pid])) {
                    $all[$id] = $entry;
                    $all[$pid]['children'][] = & $all[$id];
                    unset($dangling[$entry['id']]);
                }
            }
        }

        return $output;
    }

    /**
     * @param string $slug
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getCategoryBySlug(string $slug, Eshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_NewsCategory object');
        $query->select('object.*, file.*, newsCategoryLangs.*, newsCategories.*, subNewsCategoryLangs.*');
        $query->addSelect('newsCategoryLangs.Name as Name, newsCategoryLangs.Description as Description, newsCategoryLangs.ShortDescription as ShortDescription, newsCategoryLangs.slug as slug');
        $query->leftJoin('object.file file');
        $query->leftJoin('object.newsCategoryLangs newsCategoryLangs WITH newsCategoryLangs.Language_ID = ?', $eshop->Language_ID);
        $query->where('newsCategoryLangs.slug = ?', $slug);
        $query->leftJoin('object.newsCategories newsCategories');
        $query->leftJoin('newsCategories.newsCategoryLangs subNewsCategoryLangs WITH subNewsCategoryLangs.Language_ID = ?', $eshop->Language_ID);
        $category = $query->execute()->toArray();

        return $category ? $category[0] : [];
    }

